.darma-loader-darma-custom-530 {color: var(--loader-color, #e11d48);
   display: inline-flex;
   gap: 10px;
}
.darma-loader-darma-custom-530:before, .darma-loader-darma-custom-530:after  {
  content: "";
   height: 20px;
   aspect-ratio: 1;
   border-radius: 50%;
   background: radial-gradient(farthest-side,currentColor 95%,#0000) 35% 35%/6px 6px no-repeat currentColor;
   transform: scaleX(var(--s,1)) rotate(0deg);
   animation: darma-loader-darma-custom-530-l6 1s infinite linear;
}
.darma-loader-darma-custom-530:after  {
  --s: -1;
   animation-delay:-0.1s;
}
@keyframes darma-loader-darma-custom-530-l6  {
  100% {transform:scaleX(var(--s,1)) rotate(360deg);
}
}

